export default function StackIcon({ name, variant = "light", className, style }: StackIconProps) {
  const normalized = name.toLowerCase();
  const icon = iconsMap[normalized] || iconsMap[name];
  
  if (!icon) {
    console.warn(`StackIcon: Icon not found for "${name}"`);
    return null;
  }

  const svgString = icon.svg[variant] || icon.svg["light"];

  return (
    <div
      className={className}
      style={{
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
        width: "100%",
        height: "100%",
        ...style
      }}
      dangerouslySetInnerHTML={{ __html: svgString }}
    />
  );
}
